mapper.select:
SELECT NVL(COUNT(*), 0)
FROM space s


		( INSTR(space_name, #{kwd}) > 0 OR INSTR(space_intro, #{kwd}) > 0 )


		AND category_no = #{category}


		AND region = #{region}

	AND status = 'ACTIVE' AND is_premium = 'Y'

SELECT s.space_no AS num, space_name AS name, '0' AS rating, '0' AS review_num, region AS address, max_capacity AS capacity, price_per_hour AS price, '0' AS isWished, thumbnail_url AS thumbnail FROM space s LEFT JOIN ( SELECT su.*, ROW_NUMBER() OVER (PARTITION BY su.space_no ORDER BY su.unit_no ) rn FROM space_unit su ) su ON s.space_no = su.space_no AND su.rn = 1
( INSTR(space_name, #{kwd}) > 0 OR INSTR(space_intro, #{kwd}) > 0 )
AND category_no = #{category}
AND region = #{region}
AND status = 'ACTIVE' AND is_premium = 'Y'

SELECT NVL(COUNT(*), 0)
FROM space s


		( INSTR(space_name, #{kwd}) > 0 OR INSTR(space_intro, #{kwd}) > 0 )


		AND category_no = #{category}


		AND region = #{region}

	AND status = 'ACTIVE'

SELECT s.space_no AS num, space_name AS name, '0' AS rating, '0' AS review_num, region AS address, max_capacity AS capacity, price_per_hour AS price, '0' AS isWished, thumbnail_url AS thumbnail FROM space s LEFT JOIN ( SELECT su.*, ROW_NUMBER() OVER (PARTITION BY su.space_no ORDER BY su.unit_no ) rn FROM space_unit su ) su ON s.space_no = su.space_no AND su.rn = 1
( INSTR(space_name, #{kwd}) > 0 OR INSTR(space_intro, #{kwd}) > 0 )
AND category_no = #{category}
AND region = #{region}
AND status = 'ACTIVE'

SELECT thumbnail_url
FROM space_unit
WHERE space_no = #{space_no}
